#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    int countDistinctSubstrings(string s) {
        unordered_set<string> substrings;
        for (int i = 0; i < s.size(); i++) {
            string current_substring = "";
            for (int j = i; j < s.size(); j++) {
                current_substring += s[j];
                substrings.insert(current_substring);
            }
        }
        return substrings.size();
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    cin.ignore();
    string s;
    getline(cin, s);
    Solution sol;
    int ans = sol.countDistinctSubstrings(s);
    cout << ans << "\n";
    return 0;
}
